\begin{align*}
\mathbf{n} - \mathbf{c} &= \frac{\mathbf{a} + 2 \mathbf{b} + \mathbf{d}}{4} - \left( \frac{1 + \sqrt{3}}{2} \mathbf{a} - \frac{\sqrt{3}}{2} \mathbf{b} + \frac{1}{2} \mathbf{d} \right) \\
