&= \frac{(1 + \sqrt{3})^2}{16} \|\mathbf{a}\|^2 + \frac{(1 + \sqrt{3})^2}{4} \|\mathbf{b}\|^2 + \frac{1}{16} \|\mathbf{d}\|^2 \\
