pair A, B, C, H, Hp, O;

O = (0,0);
A = dir(110);
B = dir(200);
C = dir(330);
H = orthocenter(A,B,C);
Hp = reflect(B,C)*(H);

draw(Circle(O,1));
draw(A--B--C--cycle);
draw(A--H);
draw(H--Hp);

label("$A$", A, N);
